mapper.insert:
INSERT INTO report (
target_id, target_type, user_id, reason, content, report_status, created_at
) VALUES (
#{targetId}, #{targetType}, #{userId}, #{reason}, #{content}, 'PENDING', NOW()
)

mapper.select:
SELECT r.id, r.target_type, r.target_id, r.user_id, u.login_id AS reporterName, r.reason, r.content, r.report_status, r.created_at, r.updated_at, f.file_path FROM report r LEFT JOIN user u ON r.user_id = u.id LEFT JOIN file f ON f.target_id = r.id AND f.target_type = 'REPORT'
AND r.report_status = #{reportStatus}
ORDER BY r.created_at DESC
